code = """import json
import pandas as pd

# Load previous tool results from storage variables
reviews = var_call_QjaXnzQrbbWU2T7JqeLQeTpy  # list of dicts from review query
books_file = var_call_QKEDYtdCOZBMWlzm5psNpOGv  # path to JSON file containing books query result

# Read the books JSON file
with open(books_file, 'r', encoding='utf-8') as f:
    books = json.load(f)

# Create DataFrames
df_reviews = pd.DataFrame(reviews)
# Ensure avg_rating and review_count are numeric
if not df_reviews.empty:
    df_reviews['avg_rating'] = pd.to_numeric(df_reviews['avg_rating'])
    df_reviews['review_count'] = pd.to_numeric(df_reviews['review_count'])

df_books = pd.DataFrame(books)

# Map purchase_id to book_id by replacing prefix
if not df_reviews.empty:
    df_reviews['mapped_book_id'] = df_reviews['purchase_id'].str.replace('purchaseid_', 'bookid_')
else:
    df_reviews['mapped_book_id'] = []

# Normalize text fields for matching
for col in ['categories', 'details', 'title', 'author']:
    if col in df_books.columns:
        df_books[col] = df_books[col].fillna('').astype(str)

# Merge on mapped_book_id == book_id
merged = pd.merge(df_reviews, df_books, left_on='mapped_book_id', right_on='book_id', how='left')

# Filter for Literature & Fiction and English
def contains_lit_fic(x):
    return 'literature & fiction' in x.lower()

def contains_english(x):
    return 'english' in x.lower()

matched = merged[merged['categories'].apply(lambda x: contains_lit_fic(x) if isinstance(x, str) else False) & (
    merged['categories'].apply(lambda x: contains_english(x) if isinstance(x, str) else False) |
    merged['details'].apply(lambda x: contains_english(x) if isinstance(x, str) else False)
)]

# Prepare output records
output = []
for _, row in matched.iterrows():
    output.append({
        'purchase_id': row.get('purchase_id'),
        'book_id': row.get('book_id'),
        'title': row.get('title'),
        'author': row.get('author'),
        'avg_rating': float(row.get('avg_rating')) if pd.notnull(row.get('avg_rating')) else None,
        'review_count': int(row.get('review_count')) if pd.notnull(row.get('review_count')) else None,
        'categories': row.get('categories'),
        'details': row.get('details')
    })

# If no matches found, return empty list
result_json = json.dumps(output)
print("__RESULT__:")
print(result_json)"""

